# pip install anthropic httpx
import httpx, json, asyncio
from anthropic import Anthropic

client = Anthropic()

# Each sub-orchestrator runs as its own service.
SUB_ORCHESTRATORS = {
    "research":  "http://localhost:8010",
    "analysis":  "http://localhost:8011",
    "report":    "http://localhost:8012",
}

TOP_LEVEL_TOOLS = [
    {
        "name": "research",
        "description": "Gather information: web search, news, and document retrieval.",
        "input_schema": {
            "type": "object",
            "properties": {
                "topic": {"type": "string"},
                "depth": {"type": "string", "enum": ["quick", "deep"], "default": "deep"},
            },
            "required": ["topic"],
        },
    },
    {
        "name": "analysis",
        "description": "Analyse research findings: run code, generate charts, extract insights.",
        "input_schema": {
            "type": "object",
            "properties": {
                "research_output": {"type": "string"},
                "analysis_type": {"type": "string", "description": "e.g. trend, comparison, root-cause"},
            },
            "required": ["research_output", "analysis_type"],
        },
    },
    {
        "name": "report",
        "description": "Write, format, and optionally send a report from the analysis output.",
        "input_schema": {
            "type": "object",
            "properties": {
                "analysis_output": {"type": "string"},
                "format":  {"type": "string", "enum": ["pdf", "email", "markdown"], "default": "markdown"},
                "send_to": {"type": "string", "description": "email address, optional"},
            },
            "required": ["analysis_output", "format"],
        },
    },
]

async def call_sub_orchestrator(name: str, inputs: dict) -> str:
    base = SUB_ORCHESTRATORS[name]
    async with httpx.AsyncClient(timeout=120) as c:
        try:
            resp = await c.post(f"{base}/run", json=inputs)
            resp.raise_for_status()
            return resp.text
        except httpx.HTTPError as exc:
            return json.dumps({"error": str(exc), "orchestrator": name})

async def top_level_orchestrator(user_goal: str) -> str:
    messages = [{"role": "user", "content": user_goal}]
    system = (
        "You are a top-level orchestrator. Break the user's goal into research, analysis, "
        "and report phases. Call each sub-orchestrator in the right order — research first, "
        "then analysis using research output, then report using analysis output."
    )
    while True:
        resp = client.messages.create(
            model="claude-sonnet-5",
            max_tokens=2000,
            tools=TOP_LEVEL_TOOLS,
            system=system,
            messages=messages,
        )
        if resp.stop_reason == "end_turn":
            return next((b.text for b in resp.content if b.type == "text"), "")

        # Note: these sub-orchestrators are SEQUENTIAL (each depends on the last)
        # but the top-level model will naturally call them one at a time
        tool_results = []
        for block in resp.content:
            if block.type == "tool_use":
                result = await call_sub_orchestrator(block.name, block.input)
                tool_results.append({"type": "tool_result", "tool_use_id": block.id, "content": result})

        messages += [
            {"role": "assistant", "content": resp.content},
            {"role": "user", "content": tool_results},
        ]

