from fastapi import FastAPI
from pydantic import BaseModel
from anthropic import Anthropic
import asyncio, httpx, json

app = FastAPI()
client = Anthropic()

RESEARCH_TOOLS = [
    {
        "name": "web_search",
        "description": "Search the web for information on a topic.",
        "input_schema": {"type": "object", "properties": {"query": {"type": "string"}}, "required": ["query"]},
    },
    {
        "name": "news_search",
        "description": "Search recent news articles.",
        "input_schema": {"type": "object", "properties": {"query": {"type": "string"}, "days": {"type": "integer", "default": 7}}, "required": ["query"]},
    },
    {
        "name": "read_pdf",
        "description": "Extract and summarise text from a PDF URL.",
        "input_schema": {"type": "object", "properties": {"url": {"type": "string"}}, "required": ["url"]},
    },
]

def execute_research_tool(name: str, inputs: dict) -> str:
    # Placeholder implementations
    if name == "web_search":
        return json.dumps({"results": [f"Web result for: {inputs['query']}"]})
    if name == "news_search":
        return json.dumps({"articles": [f"News: {inputs['query']} ({inputs.get('days',7)} days)"]})
    if name == "read_pdf":
        return json.dumps({"text": f"PDF content from {inputs['url'][:50]}..."})
    return json.dumps({"error": "unknown"})

class RunRequest(BaseModel):
    topic: str
    depth: str = "deep"

@app.post("/run")
async def run(req: RunRequest) -> dict:
    messages = [{"role": "user", "content": f"Research '{req.topic}' in {req.depth} depth."}]
    system = "You are a research agent. Use web search, news search, and PDF reading to gather comprehensive information."

    while True:
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",   # cheaper model for research
            max_tokens=1200,
            tools=RESEARCH_TOOLS,
            system=system,
            messages=messages,
        )
        if resp.stop_reason == "end_turn":
            text = next((b.text for b in resp.content if b.type == "text"), "")
            return {"output": text, "orchestrator": "research"}

        # Run all tool calls in this turn in parallel
        tool_blocks = [b for b in resp.content if b.type == "tool_use"]
        results = [execute_research_tool(b.name, b.input) for b in tool_blocks]
        tool_results = [
            {"type": "tool_result", "tool_use_id": b.id, "content": r}
            for b, r in zip(tool_blocks, results)
        ]
        messages += [
            {"role": "assistant", "content": resp.content},
            {"role": "user", "content": tool_results},
        ]

@app.get("/health")
async def health():
    return {"status": "ok"}

