import json

@dataclass
class ResearchOutput:
    topic: str
    sources: list[dict]
    summary: str
    key_facts: list[str]

@dataclass
class AnalysisOutput:
    insights: list[str]
    chart_data: dict | None
    code_output: str | None
    recommendation: str

def pass_context_to_analysis(research: ResearchOutput) -> str:
    """Serialise research output as the analysis orchestrator's input."""
    return json.dumps({
        "research_output": json.dumps(asdict(research)),
        "analysis_type": "trend",
    })

