import httpx, asyncio, json

class CircuitBreaker:
    def __init__(self, failure_threshold: int = 3, recovery_seconds: int = 60):
        self._failures: dict[str, int] = {}
        self._open_until: dict[str, float] = {}
        self._threshold = failure_threshold
        self._recovery = recovery_seconds

    def is_open(self, service: str) -> bool:
        import time
        open_until = self._open_until.get(service, 0.0)
        if time.time() < open_until:
            return True
        if time.time() >= open_until and service in self._open_until:
            # Reset after recovery period
            self._failures[service] = 0
            del self._open_until[service]
        return False

    def record_failure(self, service: str) -> None:
        import time
        self._failures[service] = self._failures.get(service, 0) + 1
        if self._failures[service] >= self._threshold:
            self._open_until[service] = time.time() + self._recovery

    def record_success(self, service: str) -> None:
        self._failures[service] = 0

breaker = CircuitBreaker()

async def call_with_retry(service: str, url: str, inputs: dict,
                           max_retries: int = 3) -> str:
    if breaker.is_open(service):
        return json.dumps({"error": "circuit_open", "service": service})

    for attempt in range(max_retries):
        try:
            async with httpx.AsyncClient(timeout=60) as c:
                resp = await c.post(url, json=inputs)
                resp.raise_for_status()
                breaker.record_success(service)
                return resp.text
        except httpx.HTTPError as exc:
            breaker.record_failure(service)
            if attempt < max_retries - 1:
                await asyncio.sleep(2 ** attempt)   # 1s, 2s, 4s
            else:
                return json.dumps({"error": str(exc), "service": service})
    return json.dumps({"error": "max_retries_exceeded"})
